Now for the Prisma schema:
```prisma
generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

enum DebtStatus {
  ACTIVE
  PAID
  CANCELLED
}

model User {
  id        String   @id @default(cuid())
  name      String
  email     String   @unique
  password  String
  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  createdDebts Debt[] @relation("CreatedDebts")
  owedDebts    Debt[] @relation("OwedDebts")
  payments     Payment[]
}

model Debt {
  id          String     @id @default(cuid())
  title       String
  description String?
  totalAmount Float
  status      DebtStatus @default(ACTIVE)
  createdAt   DateTime   @default(now())
  updatedAt   DateTime   @updatedAt

  createdById String
  createdBy   User   @relation("CreatedDebts", fields: [createdById], references: [id])

  owedToId String
  owedTo   User   @relation("OwedDebts", fields: [owedToId], references: [id])

  payments Payment[]
}

model Payment {
  id        String   @id @default(cuid())
  amount    Float
  receipt   String?
  notes     String?
  paidAt    DateTime @default(now())
  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  debtId  String
  debt    Debt   @relation(fields: [debtId], references: [id])

  paidById String
  paidBy   User   @relation(fields: [paidById], references: [id])
}
```

Now let me create the server's index.ts bootstrap:

```typescript
import express from "express";
import cors from "cors";
import helmet from "helmet";
import dotenv from "dotenv";
import cookieParser from "cookie-parser";
import morgan from "morgan";

dotenv.config();

const app = express();
const PORT = process.env.PORT || 3000;

// Middleware
app.use(helmet());
app.use(cors({
  origin: process.env.CLIENT_URL || "http://localhost:5173",
  credentials: true,
}));
app.use(express.json());
app.use(cookieParser());
app.use(morgan("dev"));

// Routes (temporal)
app.get("/api/health", (_req, res) => {
  res.json({ status: "ok", timestamp: new Date().toISOString() });
});

// Start server
app.listen(PORT, () => {
  console.log(`Server running on http://localhost:${PORT}`);
});
```

